module brent_kung_adder (
    input [3:0] A,
    input [3:0] B,
    output [3:0] SUM,
    output COUT
);
    wire [3:0] G, P; // Generate and Propagate
    wire [3:0] obf_C;    // Carry bits

    // Generate and Propagate signals
    assign G = A & B; // Generate
    assign P = A ^ B; // Propagate

    // Carry generation
    assign obf_C[0] = G[0];
    assign obf_C[1] = G[1] | (P[1] & obf_C[0]);
    assign obf_C[2] = G[2] | (P[2] & obf_C[1]);
    assign obf_C[3] = G[3] | (P[3] & obf_C[2]);

    // Sum calculation
    assign SUM = P ^ {obf_C[2:0], 1'b0};
    assign COUT = obf_C[3];

endmodule
